{"type": "email", "id": "email_001", "subject": "Q2 Sales Target Review", "from": "ryan.thompson@elexionautomotive.com", "from_name": "Ryan Thompson", "to": ["michael.jones@elexionautomotive.com"], "cc": ["sarah.williams@elexionautomotive.com"], "date": "2024-03-02 09:00:00", "body": "Hi Michael, 

